const input = $input.first().json;
const ledgerContent = input.ledgerContent;
const entryCount = input.entryCount;
const emailIds = input.emailIds || [];
const today = new Date().toISOString().split('T')[0];

const binaryData = Buffer.from(ledgerContent + '\n', 'utf-8');

return [{
  json: {
    entryCount: entryCount,
    fileName: `ledger-entries-${today}.ledger`,
    emailIds: emailIds
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/plain',
      fileName: `ledger-entries-${today}.ledger`,
      fileExtension: 'ledger'
    }
  }
}];

