// Get the raw response from Gemini
const item = $input.first().json;

let text = '';

// Try multiple possible response structures
if (item?.content?.parts) {
  text = item.content.parts.map(p => p.text || '').join('');
} else if (item?.candidates) {
  text = item.candidates
    .map(c => c.content?.parts?.map(p => p.text || '').join('') || '')
    .join('');
} else if (item?.message?.content) {
  text = item.message.content;
} else if (item?.text) {
  text = item.text;
} else if (item?.output) {
  text = item.output;
} else {
  text = JSON.stringify(item);
}

// FIX: Handle JSON arrays by joining all elements instead of taking just the first one
try {
  const parsed = JSON.parse(text);
  if (Array.isArray(parsed)) {
    // Join all array elements with double newlines to separate transactions
    text = parsed.filter(item => typeof item === 'string').join('\n\n');
  } else if (typeof parsed === 'string') {
    text = parsed;
  }
} catch (e) {
  // Not JSON or parsing failed, use text as-is
}

// Clean up formatting
text = text.replace(/\\n/g, '\n').trim();

const lines = text.split('\n');
const filteredLines = lines.filter(line => line.trim() !== 'SKIP' && line.trim() !== '');
const ledgerContent = filteredLines.join('\n').trim();

if (!ledgerContent || ledgerContent === 'SKIP') {
  return [{ json: { hasEntries: false, ledgerContent: '' } }];
}

// Count entries (each entry starts with a date pattern YYYY/MM/DD)
const entryCount = (ledgerContent.match(/^\d{4}\/\d{2}\/\d{2}/gm) || []).length;

// Get Email IDs from previous node
const aggregatedItems = $('Aggregate All Emails').first().json;
const emailIds = (aggregatedItems.data || []).map(item => item.id).filter(Boolean);

return [{ 
  json: { 
    hasEntries: true, 
    ledgerContent: ledgerContent,
    entryCount: entryCount,
    generatedAt: new Date().toISOString(),
    emailIds: emailIds
  } 
}];

const items = $input.first().json.data || [];

const cleaned = items.map(item => {
  let body = '';

  // If no plain text, extract from HTML
  if (!body && item.html) {
    let html = item.html;

    // Extract transaction text from SBI Card emails (brown highlight box)
    const sbiMatch = html.match(/bgcolor="#a26d2b"[^>]*>([\s\S]*?)<\/td>/gi);
    if (sbiMatch) {
      body = sbiMatch.map(m => m.replace(/<[^>]*>/g, ' ')).join('\n');
    }

    // Extract transaction text from ICICI emails
    const iciciMatch = html.match(/transaction[^<]*(?:rs\.?|inr|₹)\s*[\d,]+\.?\d*/gi);
    if (iciciMatch) {
      body += '\n' + iciciMatch.join('\n');
    }

    // Extract transaction text from Federal Bank emails
    const fedMatch = html.match(/(?:debited|credited|spent)[^<]*(?:rs\.?|inr|₹)\s*[\d,]+\.?\d*/gi);
    if (fedMatch) {
      body += '\n' + fedMatch.join('\n');
    }

    // If none of the specific patterns matched, do a general HTML cleanup
    if (!body.trim()) {
      body = html
        .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
        .replace(/<img[^>]*>/gi, '')
        .replace(/<[^>]*>/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&#39;/g, "'")
        .replace(/\s+/g, ' ')
        .trim();
    }
  }

  // Clean up whitespace
  body = body.replace(/\s+/g, ' ').trim();

  // Trim to 3000 chars per email to save tokens
  body = body.substring(0, 3000);

  return { ...item, cleanBody: body };
});

return [{ json: { data: cleaned } }];
